public class Main {
    public static void main(String[] args) throws Exception {
        java.io.BufferedReader br = new java.io.BufferedReader(new java.io.InputStreamReader(System.in));
        java.util.StringTokenizer st = new java.util.StringTokenizer(br.readLine());
        int T = Integer.parseInt(st.nextToken());
        StringBuilder output = new StringBuilder();
        while (T-- > 0) {
            st = new java.util.StringTokenizer(br.readLine());
            int n = Integer.parseInt(st.nextToken());
            int m = Integer.parseInt(st.nextToken());
            java.util.List<Integer>[] adj = new java.util.ArrayList[n];
            for (int i = 0; i < n; i++) adj[i] = new java.util.ArrayList<>();
            for (int i = 0; i < m; i++) {
                st = new java.util.StringTokenizer(br.readLine());
                int u = Integer.parseInt(st.nextToken()) - 1;
                int v = Integer.parseInt(st.nextToken()) - 1;
                adj[u].add(v);
                adj[v].add(u);
            }
            for (int i = 0; i < n; i++) java.util.Collections.sort(adj[i]);
            boolean[] visited = new boolean[n];
            StringBuilder order = new StringBuilder();
            dfs(0, adj, visited, order);
            output.append(order.toString().trim()).append('\n');
        }
        System.out.print(output.toString());
    }
    private static void dfs(int u, java.util.List<Integer>[] adj, boolean[] visited, StringBuilder order) {
        visited[u] = true;
        order.append(u + 1).append(' ');
        for (int v : adj[u]) {
            if (!visited[v]) dfs(v, adj, visited, order);
        }
    }
}

